#include<stdio.h>
int main()
{
    int a[6]={0};
    int i,j,temp=0,k1=0,k2=0,k3=0;
    for(i=0;i<6;i++)
        scanf("%d",&a[i]);
    for(i=0;i<6;i++)
    {
        for(j=0;j<6;j++)
        {
            if(a[i]>a[j])
            {
                temp=a[i];
                a[i]=a[j];
                a[j]=temp;
            }
        }
    }


    if(a[1]==a[2] && a[2]==a[3] && a[3]==a[4])
    {
        k1=1;
        if(a[0]==a[5])
            k2=1;
        else
            k3=1;
    }
    else if(a[2]==a[3] && a[3]==a[4] && a[4]==a[5])
    {
        k1=1;
        if(a[0]==a[1])
            k2=1;
        else
            k3=1;

    }
    else if(a[0]==a[1] && a[1]==a[2] && a[2]==a[3])
    {
        k1=1;
        if(a[4]==a[5])
            k2=1;
        else
            k3=1;
    }
    if(k1==1 && k2==1)
        printf("Elephant\n");
    else if(k1==1 && k3==1)
        printf("Bear\n");
    else
        printf("Alien\n");

        return 0;



}

